{"code": "import json
import re

# Load German patents data
result_path = locals()['var_functions.query_db:42']
with open(result_path, 'r') as f:
    all_patents = json.load(f)

# Helper functions
def get_year(date_str):
    if not date_str:
        return None
    match = re.search(r'\b(20\d{2})\b', str(date_str))
    return int(match.group(1)) if match else None

def is_second_half(date_str):
    if not date_str or '2019' not in str(date_str):
        return False
    return bool(re.search(r'(Jul|Aug|Sep|Oct|Nov|Dec)', str(date_str), re.IGNORECASE))

# Process patents
sh_2019_patents = []
cpc_yearly_counts = {}
cpc_codes_sh_2019 = set()

for patent in all_patents:
    grant_date = patent.get('grant_date', '')
    year = get_year(grant_date)

    if year:
        # Count CPC codes by year for EMA
        cpc_data = patent.get('cpc', '')
        if cpc_data:
            try:
                cpc_list = json.loads(cpc_data)
                year_codes = set()

                for item in cpc_list:
                    code = item.get('code', '')
                    # Extract level 4 CPC code (main group)
                    if code and '/' in code:
                        level4 = code.split('/')[0]
                        year_codes.add(level4)

                if year not in cpc_yearly_counts:
                    cpc_yearly_counts[year] = {}

                for code in year_codes:
                    cpc_yearly_counts[year][code] = cpc_yearly_counts[year].get(code, 0) + 1
            except:
                pass

    # Check if in second half 2019
    if year == 2019 and is_second_half(grant_date):
        sh_2019_patents.append(patent)
        # Collect CPC codes for these patents
        cpc_data = patent.get('cpc', '')
        if cpc_data:
            try:
                cpc_list = json.loads(cpc_data)
                for item in cpc_list:
                    code = item.get('code', '')
                    if code and '/' in code:
                        level4 = code.split('/')[0]
                        cpc_codes_sh_2019.add(level4)
            except:
                pass

# Report findings
years = sorted(cpc_yearly_counts.keys())
output = 'Analysis Results:\n'
output += 'German patents in second half 2019: ' + str(len(sh_2019_patents)) + '\n'
output += 'Available years: ' + str(years) + '\n'
output += 'CPC level 4 codes in second half 2019: ' + str(len(cpc_codes_sh_2019)) + '\n'

if 2019 in cpc_yearly_counts:
    cpc_2019 = cpc_yearly_counts[2019]
    output += 'Total CPC codes in 2019: ' + str(len(cpc_2019)) + '\n'

    # Get top 15
    top_15 = sorted(cpc_2019.items(), key=lambda x: x[1], reverse=True)[:15]
    output += 'Top 15 CPC codes in 2019:\n'
    for code, count in top_15:
        output += '  ' + code + ': ' + str(count) + '\n'
else:
    top_15 = []
    output += 'No 2019 CPC data found\n'

print(output)

# Save data for next steps
result_dict = {
    'sh_2019_count': len(sh_2019_patents),
    'years': years,
    'cpc_codes_sh_2019': list(cpc_codes_sh_2019),
    'cpc_yearly_counts': cpc_yearly_counts,
    'top_15_2019': top_15
}

print('__RESULT__:')
print(json.dumps(result_dict))"}

