{"code": "import json
import re

# Load the German patents data for 2019
result_path = locals()['var_functions.query_db:48']
with open(result_path, 'r') as f:
    patents_2019 = json.load(f)

print('Total 2019 German patents loaded:', len(patents_2019))

# Identify second half 2019 patents
def is_second_half(date_str):
    if not date_str:
        return False
    return bool(re.search(r'(Jul|Aug|Sep|Oct|Nov|Dec)', str(date_str), re.IGNORECASE))

# Filter for second half 2019
sh_2019_patents = [p for p in patents_2019 if is_second_half(p.get('grant_date', ''))]
print('Second half 2019 patents:', len(sh_2019_patents))

# Get CPC codes from these patents
cpc_codes_sh_2019 = set()
for patent in sh_2019_patents:
    cpc_data = patent.get('cpc', '')
    if not cpc_data:
        continue
    try:
        cpc_list = json.loads(cpc_data)
        for item in cpc_list:
            code = item.get('code', '')
            if code and '/' in code:
                # Level 4 CPC: take part before /
                level4 = code.split('/')[0]
                cpc_codes_sh_2019.add(level4)
    except:
        continue

print('Unique CPC level 4 codes in second half 2019:', len(cpc_codes_sh_2019))

# Now we need data for EMA calculation - query all German patents
print('Need to query all German patents for historical data...')

result = {
    'sh_2019_patents': len(sh_2019_patents),
    'cpc_codes_sh_2019': list(cpc_codes_sh_2019)
}

print('__RESULT__:')
print(json.dumps(result))"}

